mapper.sql:
FROM rs_result_file rf LEFT JOIN rs_task t ON t.id = rf.task_id LEFT JOIN rs_image i ON i.id = rf.image_id WHERE rf.status = 'PUBLISHED' AND rf.layer_name IS NOT NULL AND rf.layer_name != '' AND rf.workspace IS NOT NULL AND rf.workspace != '' AND (rf.visibility = 'PUBLIC' OR rf.owner_id = #{currentUserId})
AND t.task_type = #{query.taskType}
AND rf.image_id = #{query.imageId}
AND ( rf.file_name ILIKE CONCAT('%', #{query.keyword}, '%') OR i.image_name ILIKE CONCAT('%', #{query.keyword}, '%') OR t.task_name ILIKE CONCAT('%', #{query.keyword}, '%') )

mapper.select:
SELECT


ORDER BY rf.published_at DESC NULLS LAST, rf.id DESC
LIMIT #{pageSize} OFFSET #{offset}
